(function () {
  "use strict";

  var branchId = window.ORG_BRANCH_ID;

  var $name = document.querySelector("[data-branch-name]");
  var $regionLine = document.querySelector("[data-branch-region]");
  var $statTeams = document.querySelector("[data-stat-teams]");
  var $statPlayers = document.querySelector("[data-stat-players]");
  var $teamRows = document.querySelector("[data-teams-rows]");

  function el(tag, opts, children) {
    var n = document.createElement(tag);
    if (opts) {
      if (opts.className) n.className = opts.className;
      if (opts.text != null) n.textContent = opts.text;
      if (opts.attrs) Object.keys(opts.attrs).forEach(function (k) { n.setAttribute(k, opts.attrs[k]); });
    }
    if (children) children.forEach(function (c) { n.appendChild(c); });
    return n;
  }

  async function api(url) {
    var r = await fetch(url, { headers: { "Accept": "application/json" } });
    if (!r.ok) {
      var data = null;
      try { data = await r.json(); } catch (_e) {}
      throw new Error((data && data.detail) || ("שגיאה " + r.status));
    }
    return r.json();
  }

  function emptyTeamRow(msg) {
    $teamRows.replaceChildren(
      el("tr", null, [el("td", {
        className: "org-table-empty", text: msg, attrs: { colspan: "4" },
      })])
    );
  }

  async function loadBranch() {
    try {
      var [branch, regionsResp, usersResp, teamsResp] = await Promise.all([
        api("/org/api/branches/" + branchId),
        api("/org/api/regions"),
        api("/org/api/users"),
        api("/org/api/teams?branch_id=" + encodeURIComponent(branchId)),
      ]);

      $name.textContent = branch.name || "—";

      var regionsById = {};
      (regionsResp.regions || []).forEach(function (r) { regionsById[r.id] = r; });
      var regionName = branch.region_id != null && regionsById[branch.region_id]
        ? regionsById[branch.region_id].name : "—";
      $regionLine.textContent = regionName !== "—" ? "מחוז: " + regionName : "—";

      $statTeams.textContent = String(branch.team_count != null ? branch.team_count : 0);
      $statPlayers.textContent = String(branch.player_count != null ? branch.player_count : 0);

      var coachesByUserId = {};
      (usersResp.members || []).forEach(function (m) {
        coachesByUserId[m.user_id] = m;
      });

      var teams = teamsResp.teams || [];
      if (!teams.length) {
        emptyTeamRow("אין קבוצות בסניף זה.");
        return;
      }
      $teamRows.replaceChildren.apply(
        $teamRows,
        teams.map(function (t) {
          var coach = t.user_id != null ? coachesByUserId[t.user_id] : null;
          var coachLabel = coach ? (coach.display_name || coach.email) : "—";
          return el("tr", null, [
            el("td", null, [el("strong", { text: t.team_name })]),
            el("td", null, [
              el("span", {
                className: t.division ? "org-pill" : "org-pill org-pill--muted",
                text: t.division || "—",
              }),
            ]),
            el("td", null, [
              el("span", {
                className: t.league ? "org-pill" : "org-pill org-pill--muted",
                text: t.league || "—",
              }),
            ]),
            el("td", null, [
              el("span", {
                className: coach ? "org-pill" : "org-pill org-pill--muted",
                text: coachLabel,
              }),
            ]),
          ]);
        })
      );
    } catch (e) {
      $name.textContent = "שגיאה בטעינה";
      $regionLine.textContent = e.message;
      emptyTeamRow(e.message);
    }
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", loadBranch);
  } else {
    loadBranch();
  }
})();